action.old_str:
llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls)
    self(i);
  return mMod;
}

action.new_str:
llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  fprintf(stderr, "EmitIR: TU decls=%zu\n", tu->decls.size());
  for (auto&& i : tu->decls) {
    fprintf(stderr, "EmitIR: decl name=%s kind=%d\n", i->name.c_str(), i->dcst<FunctionDecl>()?1:i->dcst<VarDecl>()?2:0);
    self(i);
  }
  return mMod;
}

